const stubBody = (title, description) => `Documentation for **${title}** is under construction.

Until this guide is written, the following are the canonical sources of truth:

- The framework source under [\`src/\`](https://github.com/pathosDev/actor-ts/tree/main/src) — heavily commented.
- The [API reference](/api/) — auto-generated from the TSDoc comments in source.
- The [\`README.md\`](https://github.com/pathosDev/actor-ts/blob/main/README.md) in the repo root.

See [\`docs/README.md\`](https://github.com/pathosDev/actor-ts/blob/main/docs/README.md) for the page template once you are filling this stub in.
`;

let created = 0;
let skipped = 0;

for (const [relPath, title, description] of PAGES) {
  const full = path.join(DOCS_DIR, relPath);
  // Also skip if the .mdx variant exists — once a stub gets promoted
  // to a real page that uses Starlight components (Tabs, Asides,
  // etc.) it gets renamed `.md` -> `.mdx`.  We shouldn't recreate
  // a plain-Markdown stub alongside it on the next scaffold run.
  const mdxVariant = full.replace(/\.md$/, '.mdx');
  if (fs.existsSync(full) || fs.existsSync(mdxVariant)) {
    skipped++;
    continue;
  }
  fs.mkdirSync(path.dirname(full), { recursive: true });
  const content =
    `---
title: ${JSON.stringify(title)}
description: ${JSON.stringify(description)}
---

${stubBody(title, description)}`;
  fs.writeFileSync(full, content, 'utf-8');
  created++;
}

console.log(`scaffold: ${created} stubs created, ${skipped} existing pages skipped (${PAGES.length} total in IA)`);
